  ('aboriginal-6f0ba476-moex-00282', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '依司法院大法官解釋，有關人民服兵役義務，下列敘述何者錯誤？', '["有關人民服兵役之重要事項，應由立法者斟酌國家安全、社會發展之需要，以法律定之", "後備軍人居住處所遷移，無故不依規定申報者，即處以刑事罰，違憲", "妨害兵役治罪條例，課予後備軍人就居住處所遷移依規定向相關機關為申報之義務，不違憲", "男子服兵役之義務，並無違反人性尊嚴，也無違反平等原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00283', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '憲法增修條文有關行政院院長與總統、副總統之規定，下列敘述何者正確？', '["行政院院長由總統提名，經立法院同意任命之", "總統或副總統因故不能視事時，由行政院院長代行其職權", "總統、副總統均缺位時，由行政院院長召集國民大會補選總統、副總統", "立法院通過不信任案後，行政院院長得呈請總統解散立法院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00284', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '關於立法院臨時會召開程序及審議事項，下列敘述何者錯誤？', '["立法院得因立法委員四分之一以上之請求而召開臨時會", "立法院臨時會以決議召集臨時會之特定事項為限", "於立法院休會期間提出不信任案，立法院應即召開臨時會審議之", "立法院於臨時會審議不信任案時，於不信任案提出72小時後，應於48小時內以記名投票表決之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00285', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '有關司法院院長之職權及地位，下列敘述何者錯誤？', '["綜理院務，監督所屬機關", "並為大法官之院長不受任期保障", "依據憲法第44條規定，出席總統主持之院際調解", "提請總統任命司法院副院長"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00286', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-6ed013db', 'sub-aboriginal-6f0ba476-06', NULL, 'single_choice', '依司法院大法官解釋，土地稅法規定，依都市計畫法指定之公共設施保留地，免徵土地增值稅；至非都市 土地經編定為交通用地，且依法核定為公共設施用地者，則不予免徵土地增值稅之規定，係違反下列何種 基本權？', '["生存權", "財產權", "工作權", "平等權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:55+00:00", "source_pdf_sha1": "384194208de1", "answer_pdf_sha1": "a334f7cbe936", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0218", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
